/* data+ :: content/quiz4.js — DA0-002 Domain 4 question bank (100 items). */
window.DATAPLUS = window.DATAPLUS || {}; DATAPLUS.questions = DATAPLUS.questions || [];
DATAPLUS.questions.push(
{ id:"D4-001", domain:4, obj:"4.1", diff:"easy", q:"An analyst must show how monthly revenue changed continuously over the last 24 months so a trend is obvious at a glance. Which chart type is the BEST choice?", options:["Pie chart","Treemap","Line chart","Histogram"], answer:2, explain:"<strong>Line chart</strong> is designed to show change in a continuous measure over an ordered time axis, making the 24-month trend immediately readable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows parts of a single whole at one point in time and cannot display a trend over 24 months.</span><span class='qd'><b>Treemap</b>: a treemap displays hierarchical proportions by area, not change over time.</span><span class='qd'><b>Histogram</b>: a histogram shows the frequency distribution of one numeric variable, not a time series.</span>" },
{ id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"A team wants to compare total sales across five regions for a single quarter. Which chart most clearly compares the categories?", options:["Scatter plot","Line chart","Bubble chart","Bar chart"], answer:3, explain:"<strong>Bar chart</strong> compares a measure across discrete categories, so five regions read cleanly side by side.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Scatter plot</b>: a scatter plot shows the relationship between two numeric variables, not category comparisons.</span><span class='qd'><b>Line chart</b>: a line chart implies continuity over an ordered axis, which is inappropriate for unordered regions.</span><span class='qd'><b>Bubble chart</b>: a bubble chart adds a third dimension via size and is overkill for a simple category comparison.</span>" },
{ id:"D4-003", domain:4, obj:"4.1", diff:"medium", q:"An analyst wants to display the relationship between advertising spend and units sold across 200 stores to look for correlation. Which visualization fits BEST?", options:["Pie chart","Scatter plot","Stacked bar chart","Waterfall chart"], answer:1, explain:"<strong>Scatter plot</strong> plots two continuous variables against each other, revealing correlation and clusters across the 200 stores.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows composition of one whole, not the relationship between two variables.</span><span class='qd'><b>Stacked bar chart</b>: a stacked bar shows part-to-whole composition across categories, not a two-variable relationship.</span><span class='qd'><b>Waterfall chart</b>: a waterfall shows sequential additions and subtractions to a running total, not correlation.</span>" },
{ id:"D4-004", domain:4, obj:"4.1", diff:"medium", q:"A finance analyst needs to show how a starting budget of $1M is increased and decreased by several line items to arrive at the final net figure. Which chart communicates this running total BEST?", options:["Waterfall chart","Histogram","Pie chart","Bubble chart"], answer:0, explain:"<strong>Waterfall chart</strong> is purpose-built to show how an initial value is changed by sequential positive and negative contributions to reach a final total.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Histogram</b>: a histogram bins a single variable's frequency and cannot show sequential gains and losses.</span><span class='qd'><b>Pie chart</b>: a pie chart shows static composition, not a cumulative running total.</span><span class='qd'><b>Bubble chart</b>: a bubble chart relates three numeric variables and does not depict a budget bridge.</span>" },
{ id:"D4-005", domain:4, obj:"4.1", diff:"easy", q:"An analyst wants to show the distribution of customer ages by grouping them into ranges (20-29, 30-39, etc.) and counting how many fall in each range. Which chart is correct?", options:["Pie chart","Line chart","Histogram","Treemap"], answer:2, explain:"<strong>Histogram</strong> groups a continuous numeric variable into bins and shows the frequency in each, exactly matching the age-range counts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows proportions of a whole, not a binned frequency distribution.</span><span class='qd'><b>Line chart</b>: a line chart tracks change over an ordered axis, not the distribution of one variable.</span><span class='qd'><b>Treemap</b>: a treemap shows hierarchical proportions by area, not numeric bins.</span>" },
{ id:"D4-006", domain:4, obj:"4.1", diff:"medium", q:"A manager wants to visualize disk usage across hundreds of folders and subfolders so the largest consumers stand out by area within their parent. Which chart fits BEST?", options:["Bar chart","Scatter plot","Line chart","Treemap"], answer:3, explain:"<strong>Treemap</strong> nests rectangles whose area encodes value, ideal for showing hierarchical proportions like folders within folders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bar chart</b>: a flat bar chart cannot show nested hierarchy and becomes unreadable with hundreds of items.</span><span class='qd'><b>Scatter plot</b>: a scatter plot relates two numeric variables and has no notion of hierarchy.</span><span class='qd'><b>Line chart</b>: a line chart shows trends over an ordered axis, not nested proportions.</span>" },
{ id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"An analyst needs one chart that shows monthly revenue as bars and the profit margin percentage as a line on a secondary axis. Which chart type does this?", options:["Stacked bar chart","Bubble chart","Combo chart","Treemap"], answer:2, explain:"<strong>Combo chart</strong> overlays two chart types (such as bars and a line) and supports a secondary axis, perfect for revenue plus margin percent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stacked bar chart</b>: a stacked bar shows composition within bars, not two different measures with separate scales.</span><span class='qd'><b>Bubble chart</b>: a bubble chart encodes three numeric variables on one plot, not bars plus a secondary-axis line.</span><span class='qd'><b>Treemap</b>: a treemap shows hierarchical area proportions and cannot mix measures on dual axes.</span>" },
{ id:"D4-008", domain:4, obj:"4.1", diff:"medium", q:"A product team wants to show, for each region, how total sales break down by product category within a single bar so both the total and the composition are visible. Which chart is BEST?", options:["Pie chart","Histogram","Stacked bar chart","Scatter plot"], answer:2, explain:"<strong>Stacked bar chart</strong> shows the total height per region while segmenting each bar by category, conveying both total and composition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows composition of only one whole, so comparing across regions requires many separate pies.</span><span class='qd'><b>Histogram</b>: a histogram bins one numeric variable and cannot break categories into sub-segments.</span><span class='qd'><b>Scatter plot</b>: a scatter plot shows relationships between two numeric variables, not category composition.</span>" },
{ id:"D4-009", domain:4, obj:"4.1", diff:"hard", q:"An analyst plots country GDP (x), life expectancy (y), and uses circle size to show population, all on one chart. Which chart type supports these three dimensions?", options:["Bubble chart","Scatter plot","Combo chart","Waterfall chart"], answer:0, explain:"<strong>Bubble chart</strong> extends a scatter plot by encoding a third numeric variable as marker size, allowing GDP, life expectancy, and population together.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Scatter plot</b>: a plain scatter plot shows only two variables and cannot encode population as size.</span><span class='qd'><b>Combo chart</b>: a combo chart mixes chart types on shared axes but does not add a size dimension to points.</span><span class='qd'><b>Waterfall chart</b>: a waterfall shows a sequential running total, not a three-variable relationship.</span>" },
{ id:"D4-010", domain:4, obj:"4.1", diff:"easy", q:"An executive deck must show how a single marketing budget is split among four channels as percentages of the whole. Which chart is the simplest fit?", options:["Pie chart","Line chart","Scatter plot","Histogram"], answer:0, explain:"<strong>Pie chart</strong> shows the parts of a single whole as proportional slices, which suits a four-way budget split.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Line chart</b>: a line chart shows change over time, not a one-time composition.</span><span class='qd'><b>Scatter plot</b>: a scatter plot relates two numeric variables and cannot show a single budget split.</span><span class='qd'><b>Histogram</b>: a histogram shows the frequency distribution of one numeric variable, not category proportions.</span>" },
{ id:"D4-011", domain:4, obj:"4.1", diff:"hard", q:"A stakeholder asks for a pie chart with 18 slices to compare 18 sales territories. As the visualization expert, what is the BEST recommendation?", options:["Keep the pie chart because it shows the whole","Use a line chart instead","Switch to a bar chart so the many categories are easy to compare and rank","Use a scatter plot of territory vs sales"], answer:2, explain:"<strong>Switch to a bar chart so the many categories are easy to compare and rank</strong> because pies become unreadable beyond a handful of slices, while bars let viewers compare and order many categories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep the pie chart because it shows the whole</b>: 18 thin similar slices are nearly impossible to compare visually, defeating the chart's purpose.</span><span class='qd'><b>Use a line chart instead</b>: a line chart implies an ordered continuous axis, which 18 unordered territories do not have.</span><span class='qd'><b>Use a scatter plot of territory vs sales</b>: a scatter plot needs two numeric variables, but territory is categorical.</span>" },
{ id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"A logistics analyst needs to show delivery volumes by U.S. state so regional patterns are visible geographically. Which visualization fits BEST?", options:["Choropleth (filled) map","Histogram","Treemap","Waterfall chart"], answer:0, explain:"<strong>Choropleth (filled) map</strong> shades geographic regions by value, making state-level volume patterns immediately visible on a map.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Histogram</b>: a histogram shows numeric frequency distribution and has no geographic dimension.</span><span class='qd'><b>Treemap</b>: a treemap shows hierarchical proportions by area, not geographic location.</span><span class='qd'><b>Waterfall chart</b>: a waterfall shows a sequential running total and cannot map regions.</span>" },
{ id:"D4-013", domain:4, obj:"4.1", diff:"medium", q:"An analyst wants viewers to drag rows and columns to dynamically summarize a sales table by region, product, and time without writing code. Which tool element is described?", options:["Pivot table","Histogram","Infographic","Choropleth map"], answer:0, explain:"<strong>Pivot table</strong> lets users drag fields into rows, columns, and values to re-summarize data interactively, matching the described behavior.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Histogram</b>: a histogram is a static frequency chart, not an interactive cross-tab summary tool.</span><span class='qd'><b>Infographic</b>: an infographic is a curated graphic narrative, not a drag-to-summarize data tool.</span><span class='qd'><b>Choropleth map</b>: a choropleth map shades geography by value and does not provide row/column summarization.</span>" },
{ id:"D4-014", domain:4, obj:"4.1", diff:"easy", q:"A nonprofit wants a single shareable graphic mixing icons, short stats, and brief text to tell its annual story to the public. Which deliverable BEST fits?", options:["Pivot table","Scatter plot","Histogram","Infographic"], answer:3, explain:"<strong>Infographic</strong> combines icons, key statistics, and concise text into a visually engaging narrative for a general audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pivot table</b>: a pivot table is an interactive analysis grid, not a polished public-facing story graphic.</span><span class='qd'><b>Scatter plot</b>: a scatter plot is a single analytical chart, not a curated multi-element graphic.</span><span class='qd'><b>Histogram</b>: a histogram is one technical chart and not a narrative infographic.</span>" },
{ id:"D4-015", domain:4, obj:"4.1", diff:"medium", q:"A dashboard uses a different color for each product line, but two of the colors are red and green sitting next to each other. What is the MOST important design concern?", options:["Color-blind users may not distinguish the two series","The chart will load slowly","The legend will be too large","The fonts will be unreadable"], answer:0, explain:"<strong>Color-blind users may not distinguish the two series</strong> because red-green color vision deficiency is common, so adjacent red and green encodings can be indistinguishable; a color-blind-safe palette or patterns are needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The chart will load slowly</b>: color choice has no meaningful effect on rendering or load time.</span><span class='qd'><b>The legend will be too large</b>: the number of colors, not the specific hues, would affect legend size.</span><span class='qd'><b>The fonts will be unreadable</b>: font readability is a separate typography concern unrelated to series color.</span>" },
{ id:"D4-016", domain:4, obj:"4.1", diff:"easy", q:"A chart shows three lines but the viewer cannot tell which line represents which product. Which design element is MISSING?", options:["Axis title","Legend","Gridline","Watermark"], answer:1, explain:"<strong>Legend</strong> maps each color or marker to its series name, which is what lets the viewer tell the three product lines apart.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Axis title</b>: an axis title labels what an axis measures, not which line is which series.</span><span class='qd'><b>Gridline</b>: gridlines aid reading values against the axis and do not identify series.</span><span class='qd'><b>Watermark</b>: a watermark is a faint background mark and conveys no series information.</span>" },
{ id:"D4-017", domain:4, obj:"4.1", diff:"medium", q:"An organization wants every report to use the same logo, color palette, and font family so outputs look consistent and professional. This practice is BEST described as:", options:["Binning","Imputation","Sampling","Branding"], answer:3, explain:"<strong>Branding</strong> is the consistent application of an organization's logo, colors, and typography across deliverables to create a unified, professional identity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Binning</b>: binning groups continuous values into ranges and is a data-prep technique, not a visual identity practice.</span><span class='qd'><b>Imputation</b>: imputation fills in missing values and has nothing to do with visual consistency.</span><span class='qd'><b>Sampling</b>: sampling selects a subset of data and is unrelated to report styling.</span>" },
{ id:"D4-018", domain:4, obj:"4.1", diff:"hard", q:"A line chart's y-axis starts at 90 instead of 0, making a 2% change look like a dramatic spike. What is the BEST critique of this design choice?", options:["Starting at 90 always improves readability","The chart needs a legend","A pie chart should be used instead","The truncated axis exaggerates the change and can mislead viewers"], answer:3, explain:"<strong>The truncated axis exaggerates the change and can mislead viewers</strong> because cutting off the baseline visually amplifies small differences, a classic distortion to avoid for honest reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Starting at 90 always improves readability</b>: a non-zero baseline is sometimes acceptable but is not universally better and here it misleads.</span><span class='qd'><b>The chart needs a legend</b>: a missing legend is unrelated to the axis-truncation distortion described.</span><span class='qd'><b>A pie chart should be used instead</b>: a pie chart cannot show a trend over time and does not fix the axis issue.</span>" },
{ id:"D4-019", domain:4, obj:"4.1", diff:"medium", q:"An analyst applies bright neon colors and three different decorative fonts across a single dashboard. Which design principle is being violated?", options:["Data versioning","Row-level security","Query optimization","Visual consistency and restraint"], answer:3, explain:"<strong>Visual consistency and restraint</strong> is violated because too many clashing colors and fonts distract from the data and undermine a clean, readable design.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data versioning</b>: data versioning concerns tracking data over time, not styling choices.</span><span class='qd'><b>Row-level security</b>: row-level security restricts data access by user and is unrelated to fonts and colors.</span><span class='qd'><b>Query optimization</b>: query optimization improves performance and has nothing to do with visual design.</span>" },
{ id:"D4-020", domain:4, obj:"4.1", diff:"easy", q:"Numbers printed directly on top of each bar so viewers can read exact values without estimating against the axis are called:", options:["Gridlines","Data labels","Legends","Tooltips"], answer:1, explain:"<strong>Data labels</strong> are the exact values printed on or near each data point so viewers do not have to estimate from the axis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Gridlines</b>: gridlines are reference lines for estimating values, not printed exact numbers.</span><span class='qd'><b>Legends</b>: a legend maps colors to series names, not exact point values.</span><span class='qd'><b>Tooltips</b>: tooltips appear only on hover and are not always-visible printed labels.</span>" },
{ id:"D4-021", domain:4, obj:"4.1", diff:"hard", q:"A team must compare conversion rates across 12 marketing campaigns and rank them from best to worst. Which chart makes ranking EASIEST?", options:["Pie chart","Line chart","Sorted (descending) bar chart","Bubble chart"], answer:2, explain:"<strong>Sorted (descending) bar chart</strong> orders the bars by value so the ranking from best to worst is read top to bottom with no effort.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart makes ranking 12 similar slices difficult and does not naturally order them.</span><span class='qd'><b>Line chart</b>: a line chart implies a continuous ordered axis, which unordered campaigns lack.</span><span class='qd'><b>Bubble chart</b>: a bubble chart relates numeric variables by position and size, not a clean ranked list.</span>" },
{ id:"D4-022", domain:4, obj:"4.1", diff:"medium", q:"An analyst wants to show the share of total support tickets handled by each of three teams across four quarters, emphasizing each team's contribution to the whole over time. Which chart is the BEST fit?", options:["Scatter plot","Histogram","100% stacked bar (or area) chart","Bubble chart"], answer:2, explain:"<strong>100% stacked bar (or area) chart</strong> normalizes each period to 100% so the changing share of each team is comparable across the four quarters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Scatter plot</b>: a scatter plot shows two-variable relationships, not part-to-whole share over time.</span><span class='qd'><b>Histogram</b>: a histogram bins one numeric variable and cannot show team shares over quarters.</span><span class='qd'><b>Bubble chart</b>: a bubble chart encodes three numeric variables and does not show composition share.</span>" },
{ id:"D4-023", domain:4, obj:"4.1", diff:"easy", q:"What does an axis title (for example, 'Revenue in USD millions') primarily provide to a chart?", options:["A faster refresh rate","Row-level access control","Context about what the axis measures and its units","A backup of the data"], answer:2, explain:"<strong>Context about what the axis measures and its units</strong> is the purpose of an axis title, preventing misreading of the values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A faster refresh rate</b>: an axis title is a label and has no effect on performance.</span><span class='qd'><b>Row-level access control</b>: access control governs who sees data, not axis labeling.</span><span class='qd'><b>A backup of the data</b>: a title is descriptive text, not a data copy.</span>" },
{ id:"D4-024", domain:4, obj:"4.1", diff:"medium", q:"A dashboard for a global brand must reinforce corporate identity. Beyond accurate data, which set of elements MOST supports a branded, professional look?", options:["More gridlines on every chart","A larger number of decimal places","Randomized chart colors per refresh","Consistent logo, corporate color palette, and approved fonts"], answer:3, explain:"<strong>Consistent logo, corporate color palette, and approved fonts</strong> are the core branding elements that make a dashboard look professional and on-brand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>More gridlines on every chart</b>: excessive gridlines add clutter and do not convey brand identity.</span><span class='qd'><b>A larger number of decimal places</b>: extra decimals reduce readability and are unrelated to branding.</span><span class='qd'><b>Randomized chart colors per refresh</b>: randomized colors break consistency, the opposite of branding.</span>" },
{ id:"D4-025", domain:4, obj:"4.1", diff:"hard", q:"An analyst has a categorical breakdown of 6 expense types for one month and chooses between a pie chart and a bar chart. The audience needs to read each value precisely. Which is the BETTER choice and why?", options:["Bar chart, because lengths are easier to compare precisely than angles","Pie chart, because slices look attractive","Pie chart, because it shows the whole","Either is identical for precision"], answer:0, explain:"<strong>Bar chart, because lengths are easier to compare precisely than angles</strong> reflects that humans judge bar length far more accurately than the angular slices of a pie, so precise reading favors the bar chart.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart, because slices look attractive</b>: aesthetics do not outweigh the audience's need to read precise values.</span><span class='qd'><b>Pie chart, because it shows the whole</b>: a bar chart can also be labeled to convey totals while remaining more precise.</span><span class='qd'><b>Either is identical for precision</b>: research consistently shows length is read more precisely than angle, so they are not equal.</span>" },
{ id:"D4-026", domain:4, obj:"4.1", diff:"medium", q:"A heat-style requirement asks an analyst to show sales intensity by store location on a map, with darker shading for higher sales. Which map type is described?", options:["Choropleth map","Network diagram","Gantt chart","Sankey diagram"], answer:0, explain:"<strong>Choropleth map</strong> uses graduated shading of geographic areas to represent value intensity, matching darker shading for higher sales.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network diagram</b>: a network diagram shows connections between nodes, not geographic intensity.</span><span class='qd'><b>Gantt chart</b>: a Gantt chart visualizes project schedules over time, not map shading.</span><span class='qd'><b>Sankey diagram</b>: a Sankey diagram shows flow magnitudes between stages, not regional shading.</span>" },
{ id:"D4-027", domain:4, obj:"4.1", diff:"easy", q:"An analyst wants to plot exact store locations as points on a geographic map. Which map type fits BEST?", options:["Histogram","Point/symbol (pin) map","Treemap","Waterfall chart"], answer:1, explain:"<strong>Point/symbol (pin) map</strong> places a marker at each store's coordinates, the right way to show discrete locations on a map.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Histogram</b>: a histogram is a non-geographic frequency chart and cannot place points on a map.</span><span class='qd'><b>Treemap</b>: a treemap shows proportions by area, not geographic points.</span><span class='qd'><b>Waterfall chart</b>: a waterfall shows a sequential running total and has no map capability.</span>" },
{ id:"D4-028", domain:4, obj:"4.1", diff:"medium", q:"An executive complains a chart has so many gridlines, borders, and 3-D effects that the data is hard to see. Removing these non-essential elements to highlight the data is known as reducing:", options:["Data lineage","Chart junk (non-data ink)","Refresh frequency","Cardinality"], answer:1, explain:"<strong>Chart junk (non-data ink)</strong> refers to decorative, non-essential elements that obscure the data; removing them improves clarity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data lineage</b>: lineage traces data's origin and transformations, not visual clutter.</span><span class='qd'><b>Refresh frequency</b>: refresh frequency is how often data updates, unrelated to gridlines and effects.</span><span class='qd'><b>Cardinality</b>: cardinality describes the uniqueness of values in a field, not chart decoration.</span>" },
{ id:"D4-029", domain:4, obj:"4.1", diff:"hard", q:"A scatter plot of 50,000 points is one dense blob where overlapping markers hide the true density. Which technique BEST reveals structure while keeping the same data?", options:["Use transparency (alpha) or a density/heat representation","Switch to a pie chart","Remove the axis titles","Increase the font size of labels"], answer:0, explain:"<strong>Use transparency (alpha) or a density/heat representation</strong> addresses overplotting by letting overlapping points blend so denser regions appear darker, revealing structure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Switch to a pie chart</b>: a pie chart cannot show the two-variable relationship of a scatter plot at all.</span><span class='qd'><b>Remove the axis titles</b>: removing titles hurts interpretation and does nothing about overplotting.</span><span class='qd'><b>Increase the font size of labels</b>: larger labels do not address overlapping markers.</span>" },
{ id:"D4-030", domain:4, obj:"4.1", diff:"medium", q:"A pivot table summarizes sales with Region in rows, Quarter in columns, and Sum of Sales in values. A manager now wants average order value instead of total. What is the SIMPLEST change?", options:["Rebuild the entire dataset","Add a new map visualization","Change the value field's aggregation/summary from Sum to Average","Switch the report to a static PDF"], answer:2, explain:"<strong>Change the value field's aggregation/summary from Sum to Average</strong> is the built-in pivot capability that re-summarizes the same field without rebuilding anything.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rebuild the entire dataset</b>: pivot tables re-aggregate on demand, so a rebuild is unnecessary work.</span><span class='qd'><b>Add a new map visualization</b>: a map does not change how the value field is aggregated.</span><span class='qd'><b>Switch the report to a static PDF</b>: exporting to PDF does not change the aggregation method.</span>" },
{ id:"D4-031", domain:4, obj:"4.1", diff:"easy", q:"Which chart is specifically intended to reveal the shape of a single numeric variable's distribution, such as whether it is skewed or bell-shaped?", options:["Pie chart","Bar chart of categories","Choropleth map","Histogram"], answer:3, explain:"<strong>Histogram</strong> bins a single continuous variable and shows its frequency shape, revealing skew or a bell curve.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows composition of a whole, not a distribution shape.</span><span class='qd'><b>Bar chart of categories</b>: a category bar chart compares discrete groups, not the distribution of one numeric variable.</span><span class='qd'><b>Choropleth map</b>: a choropleth shows geographic intensity, not a numeric distribution.</span>" },
{ id:"D4-032", domain:4, obj:"4.1", diff:"medium", q:"A column chart and a bar chart both compare categories. An analyst has very long category names (full product descriptions). Which orientation typically reads BEST and why?", options:["Vertical columns, because labels rotate cleanly","Horizontal bars, because long labels fit on the y-axis without rotation","Either, labels never matter","A pie chart, to avoid labels"], answer:1, explain:"<strong>Horizontal bars, because long labels fit on the y-axis without rotation</strong> keeps lengthy category names readable along the vertical axis instead of forcing angled column labels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vertical columns, because labels rotate cleanly</b>: rotated column labels are harder to read and often truncate.</span><span class='qd'><b>Either, labels never matter</b>: label readability matters a great deal for long names.</span><span class='qd'><b>A pie chart, to avoid labels</b>: a pie chart still needs labels and is worse for comparing many categories.</span>" },
{ id:"D4-033", domain:4, obj:"4.1", diff:"hard", q:"An analyst must show both the magnitude of monthly orders (bars) and the cumulative percentage they represent (line) to identify the vital few categories. This combination is known as a:", options:["Bubble chart","Treemap","Choropleth map","Pareto chart"], answer:3, explain:"<strong>Pareto chart</strong> is a combo of sorted bars plus a cumulative-percentage line used to spot the few categories driving most of the total.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bubble chart</b>: a bubble chart shows three numeric variables, not bars with a cumulative line.</span><span class='qd'><b>Treemap</b>: a treemap shows hierarchical area proportions, not a cumulative line.</span><span class='qd'><b>Choropleth map</b>: a choropleth shades geography by value and is unrelated to cumulative analysis.</span>" },
{ id:"D4-034", domain:4, obj:"4.1", diff:"medium", q:"A report's body font is a thin, decorative script that many users find hard to read on screen. Which typography change BEST improves readability?", options:["Add more colors to the text","Italicize every label","Use a clean sans-serif font at an adequate size","Reduce the font size to fit more text"], answer:2, explain:"<strong>Use a clean sans-serif font at an adequate size</strong> improves on-screen legibility, which is the main goal of body typography in reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more colors to the text</b>: multicolor text adds distraction and does not fix the unreadable font.</span><span class='qd'><b>Italicize every label</b>: heavy italics reduce readability rather than improve it.</span><span class='qd'><b>Reduce the font size to fit more text</b>: smaller text makes a hard-to-read font even harder to read.</span>" },
{ id:"D4-035", domain:4, obj:"4.1", diff:"easy", q:"Which design element appears only when a user hovers over a data point to reveal extra detail without cluttering the chart?", options:["Axis title","Tooltip","Gridline","Watermark"], answer:1, explain:"<strong>Tooltip</strong> displays additional details on hover, keeping the chart clean while still offering depth on demand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Axis title</b>: an axis title is always-visible label text, not an on-hover detail popup.</span><span class='qd'><b>Gridline</b>: gridlines are static reference lines and do not respond to hovering.</span><span class='qd'><b>Watermark</b>: a watermark is a fixed background mark, not interactive hover detail.</span>" },
{ id:"D4-036", domain:4, obj:"4.1", diff:"medium", q:"An analyst wants the highest-value category in a bar chart to draw the eye while others recede. Which color approach BEST achieves this?", options:["Use a different bright color for every bar","Color all bars the same bright red","Remove all color","Use a single accent color on the key bar and a neutral gray for the rest"], answer:3, explain:"<strong>Use a single accent color on the key bar and a neutral gray for the rest</strong> applies selective emphasis so the important value stands out against muted context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use a different bright color for every bar</b>: a rainbow of colors competes for attention and emphasizes nothing.</span><span class='qd'><b>Color all bars the same bright red</b>: identical bright coloring gives no single bar emphasis.</span><span class='qd'><b>Remove all color</b>: removing color entirely removes the ability to highlight the key category.</span>" },
{ id:"D4-037", domain:4, obj:"4.1", diff:"hard", q:"A stakeholder wants to visualize how website visitors flow from landing pages, to product pages, to checkout, including drop-off at each stage. Which visualization BEST shows this staged flow with magnitudes?", options:["Pie chart","Histogram","Sankey/funnel diagram","Scatter plot"], answer:2, explain:"<strong>Sankey/funnel diagram</strong> depicts staged flow and the magnitude moving (and dropping off) between steps, ideal for a conversion path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pie chart</b>: a pie chart shows one static composition, not flow across stages.</span><span class='qd'><b>Histogram</b>: a histogram bins one numeric variable and cannot show staged flow.</span><span class='qd'><b>Scatter plot</b>: a scatter plot shows two-variable relationships, not sequential flow with drop-off.</span>" },
{ id:"D4-038", domain:4, obj:"4.1", diff:"medium", q:"An analyst is asked to add a legend to a single-series bar chart where every bar is the same color and already labeled on the axis. What is the BEST advice?", options:["Add three legends for safety","Omit the legend because it adds clutter without information","Color each bar differently to justify a legend","Replace the chart with a pie chart"], answer:1, explain:"<strong>Omit the legend because it adds clutter without information</strong> is correct since a single, already-labeled series needs no legend to interpret.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add three legends for safety</b>: multiple redundant legends only worsen clutter.</span><span class='qd'><b>Color each bar differently to justify a legend</b>: inventing colors to force a legend adds meaningless visual noise.</span><span class='qd'><b>Replace the chart with a pie chart</b>: changing chart types does not address whether a legend is needed.</span>" },
{ id:"D4-039", domain:4, obj:"4.1", diff:"easy", q:"What is the primary role of a chart legend?", options:["To identify what each color, pattern, or marker represents","To store the underlying data","To control who can view the report","To schedule the report refresh"], answer:0, explain:"<strong>To identify what each color, pattern, or marker represents</strong> is exactly what a legend does, mapping visual encodings to their meaning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To store the underlying data</b>: a legend is descriptive text, not a data store.</span><span class='qd'><b>To control who can view the report</b>: access control is governance, not a legend function.</span><span class='qd'><b>To schedule the report refresh</b>: scheduling is a delivery setting, not a legend role.</span>" },
{ id:"D4-040", domain:4, obj:"4.1", diff:"hard", q:"An analyst must compare quarterly sales for 8 products AND see which products are growing fastest. Which single visualization BEST serves both comparison and trend?", options:["A single pie chart","A multi-series line chart with one line per product","A single histogram","A choropleth map"], answer:1, explain:"<strong>A multi-series line chart with one line per product</strong> lets viewers compare products at each quarter while the slopes reveal which are growing fastest.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single pie chart</b>: a pie shows one period's composition and cannot display trends across quarters.</span><span class='qd'><b>A single histogram</b>: a histogram shows the distribution of one variable, not multi-product trends.</span><span class='qd'><b>A choropleth map</b>: a choropleth shows geography, not product trends over time.</span>" },
{ id:"D4-041", domain:4, obj:"4.2", diff:"easy", q:"A CEO has five minutes and wants the key findings and recommendations of a 40-page report up front. Which report component serves this need?", options:["Executive summary","Appendix","Raw data export","Data dictionary"], answer:0, explain:"<strong>Executive summary</strong> condenses the key findings, conclusions, and recommendations at the start of a report for time-pressed leaders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Appendix</b>: an appendix holds supporting detail at the end, not a concise up-front overview.</span><span class='qd'><b>Raw data export</b>: a raw export is unstructured data, not a summarized narrative.</span><span class='qd'><b>Data dictionary</b>: a data dictionary defines fields and is not a summary of findings.</span>" },
{ id:"D4-042", domain:4, obj:"4.2", diff:"medium", q:"Business users keep emailing the analytics team for slightly different cuts of the same data. Which delivery approach BEST reduces these one-off requests by letting users explore data themselves?", options:["A weekly static PDF","A printed report","A one-time spreadsheet snapshot","A self-service portal/dashboard with filters"], answer:3, explain:"<strong>A self-service portal/dashboard with filters</strong> empowers users to slice the data on their own, cutting down repetitive custom requests to the analytics team.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A weekly static PDF</b>: a fixed PDF cannot be re-sliced by users, so the requests would continue.</span><span class='qd'><b>A printed report</b>: print is the least flexible format and offers no interactivity.</span><span class='qd'><b>A one-time spreadsheet snapshot</b>: a single snapshot quickly goes stale and still requires the team for new cuts.</span>" },
{ id:"D4-043", domain:4, obj:"4.2", diff:"medium", q:"An operations team needs live KPIs that update as new transactions stream in throughout the day. Which dashboard type fits BEST?", options:["Dynamic (live/real-time) dashboard","Static PDF report","Printed handout","One-time snapshot image"], answer:0, explain:"<strong>Dynamic (live/real-time) dashboard</strong> refreshes automatically as new data arrives, suiting intraday operational KPIs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static PDF report</b>: a PDF is frozen at export time and cannot reflect streaming transactions.</span><span class='qd'><b>Printed handout</b>: print cannot update at all once produced.</span><span class='qd'><b>One-time snapshot image</b>: a snapshot captures a single moment and will not update through the day.</span>" },
{ id:"D4-044", domain:4, obj:"4.2", diff:"easy", q:"A monthly board report is finalized, signed off, and distributed as a fixed document that should not change after release. Which format is MOST appropriate?", options:["Static report (e.g., PDF)","Live interactive dashboard","Editable shared spreadsheet","Real-time streaming view"], answer:0, explain:"<strong>Static report (e.g., PDF)</strong> locks the content at the point of approval so the distributed board report cannot change after release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Live interactive dashboard</b>: a live dashboard keeps changing, which is undesirable for a signed-off board document.</span><span class='qd'><b>Editable shared spreadsheet</b>: an editable file could be altered after sign-off, undermining its integrity.</span><span class='qd'><b>Real-time streaming view</b>: streaming data would not match the figures approved by the board.</span>" },
{ id:"D4-045", domain:4, obj:"4.2", diff:"medium", q:"A finance team needs the same standardized profit-and-loss report delivered automatically on the first business day of every month. This delivery cadence is BEST described as:", options:["Ad hoc reporting","Real-time streaming","Recurring (scheduled) reporting","One-time analysis"], answer:2, explain:"<strong>Recurring (scheduled) reporting</strong> delivers a standardized report on a fixed schedule, matching the monthly first-business-day cadence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ad hoc reporting</b>: ad hoc reports answer one-off questions on demand, not a fixed schedule.</span><span class='qd'><b>Real-time streaming</b>: streaming continuously updates rather than producing a monthly deliverable.</span><span class='qd'><b>One-time analysis</b>: a one-time analysis is not repeated on a cadence.</span>" },
{ id:"D4-046", domain:4, obj:"4.2", diff:"medium", q:"An executive asks a brand-new question that requires pulling data not in any existing report, needed only once for tomorrow's meeting. This is an example of which report type?", options:["Ad hoc report","Recurring report","Standard operational dashboard","Scheduled subscription"], answer:0, explain:"<strong>Ad hoc report</strong> is a one-off, on-demand report created to answer a specific question that existing reports do not cover.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recurring report</b>: a recurring report runs on a schedule, not as a single special request.</span><span class='qd'><b>Standard operational dashboard</b>: a standard dashboard answers routine, predefined questions, not a novel one-off.</span><span class='qd'><b>Scheduled subscription</b>: a subscription delivers an existing report automatically, not a new bespoke pull.</span>" },
{ id:"D4-047", domain:4, obj:"4.2", diff:"hard", q:"A compliance team must be able to reproduce exactly what a financial dashboard showed at month-end close, even months later. Which data versioning approach BEST supports this?", options:["Snapshot (point-in-time copy) of the data","Real-time live connection only","Deleting old data each month","Disabling all caching"], answer:0, explain:"<strong>Snapshot (point-in-time copy) of the data</strong> freezes the data as it was at close, so the exact figures can be reproduced later for audit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Real-time live connection only</b>: a live connection always shows current data and cannot reproduce a past month-end state.</span><span class='qd'><b>Deleting old data each month</b>: deleting data destroys the very history needed for reproduction.</span><span class='qd'><b>Disabling all caching</b>: caching settings do not preserve a historical point-in-time view.</span>" },
{ id:"D4-048", domain:4, obj:"4.2", diff:"medium", q:"A trading desk dashboard must reflect prices as they change second by second. Which data versioning/connection approach is REQUIRED?", options:["Monthly snapshot","Real-time (live) data","Quarterly archive","Annual extract"], answer:1, explain:"<strong>Real-time (live) data</strong> continuously updates the dashboard to reflect second-by-second price changes a trading desk needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Monthly snapshot</b>: a monthly snapshot is far too stale for second-by-second trading.</span><span class='qd'><b>Quarterly archive</b>: a quarterly archive captures data once every three months and cannot drive live prices.</span><span class='qd'><b>Annual extract</b>: an annual extract is updated only once a year, useless for live trading.</span>" },
{ id:"D4-049", domain:4, obj:"4.2", diff:"easy", q:"A dashboard whose visuals never change after it is published and that contains no filters or interactivity is BEST described as:", options:["Static dashboard","Dynamic dashboard","Self-service portal","Streaming pipeline"], answer:0, explain:"<strong>Static dashboard</strong> presents fixed visuals with no interactivity or live updates after publishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dynamic dashboard</b>: a dynamic dashboard updates and offers interactivity, the opposite of static.</span><span class='qd'><b>Self-service portal</b>: a self-service portal lets users build and explore, which static visuals do not allow.</span><span class='qd'><b>Streaming pipeline</b>: a streaming pipeline moves live data, not a fixed published dashboard.</span>" },
{ id:"D4-050", domain:4, obj:"4.2", diff:"hard", q:"Leadership wants a single deliverable: a short narrative of the three biggest takeaways with a recommendation, backed by detailed charts that analysts can drill into. What is the BEST structure?", options:["Only raw data tables","A real-time stream with no summary","An executive summary up front followed by detailed supporting visuals/appendix","Just a single pie chart"], answer:2, explain:"<strong>An executive summary up front followed by detailed supporting visuals/appendix</strong> gives leaders the takeaways immediately while preserving depth for those who need it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only raw data tables</b>: raw tables bury the takeaways leadership asked for.</span><span class='qd'><b>A real-time stream with no summary</b>: a stream without a summary fails the request for a concise narrative.</span><span class='qd'><b>Just a single pie chart</b>: one chart cannot convey three takeaways plus a recommendation and detail.</span>" },
{ id:"D4-051", domain:4, obj:"4.2", diff:"medium", q:"An analytics team wants nontechnical managers to build their own filtered views from a governed dataset without SQL. Which capability BEST enables this?", options:["A self-service BI portal with a curated semantic layer","Emailing raw SQL scripts","Sending database admin passwords","Disabling all dashboards"], answer:0, explain:"<strong>A self-service BI portal with a curated semantic layer</strong> lets nontechnical users build governed views with friendly field names, no SQL required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Emailing raw SQL scripts</b>: requiring SQL defeats the goal of empowering nontechnical managers.</span><span class='qd'><b>Sending database admin passwords</b>: sharing admin credentials is a security risk and not a reporting capability.</span><span class='qd'><b>Disabling all dashboards</b>: removing dashboards leaves users with no way to explore data.</span>" },
{ id:"D4-052", domain:4, obj:"4.2", diff:"easy", q:"What is the MAIN benefit of scheduling a report to run and distribute automatically (a subscription)?", options:["It removes the need for the underlying data","It encrypts the database","It guarantees the data is always real-time","It ensures stakeholders receive timely, consistent updates without manual effort"], answer:3, explain:"<strong>It ensures stakeholders receive timely, consistent updates without manual effort</strong> is the core value of scheduled delivery: reliable, hands-off distribution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It removes the need for the underlying data</b>: a scheduled report still depends entirely on its source data.</span><span class='qd'><b>It encrypts the database</b>: scheduling is a delivery feature, not an encryption control.</span><span class='qd'><b>It guarantees the data is always real-time</b>: a scheduled report reflects data as of each run, not continuously real-time.</span>" },
{ id:"D4-053", domain:4, obj:"4.2", diff:"hard", q:"A dashboard backed by a real-time connection is slow and hammers the production database during business hours, yet users only need data accurate to the prior day. What is the BEST adjustment?", options:["Add more colors to the charts","Switch to a nightly snapshot/extract refresh instead of live querying","Make the dashboard static with no data","Remove the legend"], answer:1, explain:"<strong>Switch to a nightly snapshot/extract refresh instead of live querying</strong> matches the once-a-day accuracy need while relieving the production database of constant live queries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more colors to the charts</b>: color changes do not reduce database load or improve speed.</span><span class='qd'><b>Make the dashboard static with no data</b>: an empty dashboard fails to serve users entirely.</span><span class='qd'><b>Remove the legend</b>: removing a legend has no effect on query load or performance.</span>" },
{ id:"D4-054", domain:4, obj:"4.2", diff:"medium", q:"A team distributes a dashboard whose data is captured once and frozen, labeled 'as of Jan 31.' Which versioning concept does this represent?", options:["Streaming","Continuous integration","Snapshot","Hot standby"], answer:2, explain:"<strong>Snapshot</strong> is a frozen point-in-time capture of the data, exactly what an 'as of Jan 31' dataset is.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Streaming</b>: streaming is continuous live updating, the opposite of a frozen snapshot.</span><span class='qd'><b>Continuous integration</b>: CI is a software build/deploy practice, not a data versioning concept here.</span><span class='qd'><b>Hot standby</b>: a hot standby is a failover replica for availability, not a point-in-time data version.</span>" },
{ id:"D4-055", domain:4, obj:"4.2", diff:"easy", q:"Which audience and format pairing is MOST appropriate: senior executives who want the bottom line quickly?", options:["A 200-row raw data dump","A concise executive summary with key metrics","A full SQL transcript","A detailed schema diagram"], answer:1, explain:"<strong>A concise executive summary with key metrics</strong> matches executives who need conclusions and headline numbers fast.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A 200-row raw data dump</b>: raw rows force executives to do analysis they expect already done.</span><span class='qd'><b>A full SQL transcript</b>: SQL code is irrelevant to a business decision-maker.</span><span class='qd'><b>A detailed schema diagram</b>: a schema is a technical artifact, not an executive summary.</span>" },
{ id:"D4-056", domain:4, obj:"4.2", diff:"medium", q:"A self-service dashboard lets each regional manager see only their own region's rows automatically based on login. Which capability provides this per-user data scoping?", options:["A larger font","A static PDF export","Row-level security","A bigger color palette"], answer:2, explain:"<strong>Row-level security</strong> filters the data each user sees based on their identity, so a manager sees only their region.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger font</b>: font size has nothing to do with restricting which rows a user sees.</span><span class='qd'><b>A static PDF export</b>: a PDF shows the same fixed content to everyone, not per-user scoping.</span><span class='qd'><b>A bigger color palette</b>: color choices do not control data visibility by user.</span>" },
{ id:"D4-057", domain:4, obj:"4.2", diff:"hard", q:"An analyst must choose between a snapshot and a real-time feed for a sales-forecasting model that is rebuilt weekly and must be exactly reproducible by auditors. Which is MORE appropriate and why?", options:["Real-time feed, because newer is always better","Real-time feed, because it reduces storage","Snapshot, because it is always more accurate than live data","Snapshot, because a fixed dataset makes the weekly model reproducible and auditable"], answer:3, explain:"<strong>Snapshot, because a fixed dataset makes the weekly model reproducible and auditable</strong> ensures the same inputs can be rerun and verified, which a constantly changing live feed cannot guarantee.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Real-time feed, because newer is always better</b>: a moving target prevents exact reproduction needed by auditors.</span><span class='qd'><b>Real-time feed, because it reduces storage</b>: storage is not the decision driver here, reproducibility is.</span><span class='qd'><b>Snapshot, because it is always more accurate than live data</b>: a snapshot is not inherently more accurate; its value here is stability, not accuracy.</span>" },
{ id:"D4-058", domain:4, obj:"4.2", diff:"medium", q:"A dashboard is used by both casual viewers and power users. The team wants viewers to read curated visuals while letting power users filter and drill down. Which design BEST satisfies both?", options:["A printed handout only","A raw CSV file only","A static image with no interactivity","A dynamic dashboard with optional filters and drill-downs"], answer:3, explain:"<strong>A dynamic dashboard with optional filters and drill-downs</strong> serves casual readers with curated default views while letting power users explore on demand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A printed handout only</b>: print offers no drill-down for power users.</span><span class='qd'><b>A raw CSV file only</b>: a CSV gives no curated visuals for casual viewers.</span><span class='qd'><b>A static image with no interactivity</b>: a static image blocks the filtering power users need.</span>" },
{ id:"D4-059", domain:4, obj:"4.2", diff:"easy", q:"Which statement BEST distinguishes a static report from a dynamic dashboard?", options:["A static report is always real-time; a dynamic dashboard is frozen","They are identical in every way","A dynamic dashboard cannot contain charts","A static report is fixed at creation; a dynamic dashboard updates and is interactive"], answer:3, explain:"<strong>A static report is fixed at creation; a dynamic dashboard updates and is interactive</strong> captures the core difference between the two delivery formats.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A static report is always real-time; a dynamic dashboard is frozen</b>: this reverses the two definitions.</span><span class='qd'><b>They are identical in every way</b>: they differ fundamentally in interactivity and update behavior.</span><span class='qd'><b>A dynamic dashboard cannot contain charts</b>: dynamic dashboards are typically full of interactive charts.</span>" },
{ id:"D4-060", domain:4, obj:"4.2", diff:"hard", q:"A new self-service portal causes inconsistent numbers because each user defines 'active customer' differently in their own filters. Which governance addition BEST fixes this while keeping self-service?", options:["Banning all filters","Letting users edit the database directly","A shared, certified semantic model/metric definitions everyone uses","Switching to printed reports"], answer:2, explain:"<strong>A shared, certified semantic model/metric definitions everyone uses</strong> standardizes business definitions so self-service users get consistent numbers without losing flexibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Banning all filters</b>: removing filters destroys the self-service capability the portal exists to provide.</span><span class='qd'><b>Letting users edit the database directly</b>: direct edits introduce risk and worsen inconsistency.</span><span class='qd'><b>Switching to printed reports</b>: abandoning self-service does not solve definition consistency, it just removes the feature.</span>" },
{ id:"D4-061", domain:4, obj:"4.3", diff:"easy", q:"Users report that a dashboard takes over 60 seconds to open every morning. Which symptom category does this represent?", options:["Incorrect color scheme","Excessive load time","Missing legend","Wrong font choice"], answer:1, explain:"<strong>Excessive load time</strong> is the performance symptom where a report or dashboard takes too long to render or open.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incorrect color scheme</b>: color is a design issue and does not describe slow opening.</span><span class='qd'><b>Missing legend</b>: a missing legend is a clarity issue, not a performance delay.</span><span class='qd'><b>Wrong font choice</b>: font choice affects readability, not load time.</span>" },
{ id:"D4-062", domain:4, obj:"4.3", diff:"medium", q:"A dashboard queries a 500-million-row fact table directly on every page load and is extremely slow. Which change MOST directly reduces the data volume processed per load?", options:["Add a company logo","Change the chart colors","Pre-aggregate or extract a summarized dataset for the dashboard","Rename the dashboard"], answer:2, explain:"<strong>Pre-aggregate or extract a summarized dataset for the dashboard</strong> cuts the rows scanned per load, directly addressing the large data size driving slowness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add a company logo</b>: branding has no effect on data volume or query speed.</span><span class='qd'><b>Change the chart colors</b>: color changes do not reduce rows processed.</span><span class='qd'><b>Rename the dashboard</b>: renaming is cosmetic and changes nothing about performance.</span>" },
{ id:"D4-063", domain:4, obj:"4.3", diff:"medium", q:"A scheduled refresh that used to take 5 minutes now takes 3 hours after a new join was added. Which is the BEST FIRST troubleshooting step?", options:["Increase the font size","Review the report's query/calculation logic and the recent change","Delete the legend","Recolor the charts"], answer:1, explain:"<strong>Review the report's query/calculation logic and the recent change</strong> targets the likely cause, since the new join coincides with the slowdown.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the font size</b>: typography has no bearing on refresh duration.</span><span class='qd'><b>Delete the legend</b>: removing a legend does not affect query performance.</span><span class='qd'><b>Recolor the charts</b>: chart color changes cannot speed up a slow refresh.</span>" },
{ id:"D4-064", domain:4, obj:"4.3", diff:"hard", q:"Two reports use the same source but show different revenue totals. One was last refreshed an hour ago and the other three weeks ago. What is the MOST likely cause of the discrepancy?", options:["Different fonts","Different color palettes","Stale data in the older report due to an outdated refresh","Different chart types"], answer:2, explain:"<strong>Stale data in the older report due to an outdated refresh</strong> explains why the three-week-old report shows different totals than the recently refreshed one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Different fonts</b>: fonts are cosmetic and cannot change reported totals.</span><span class='qd'><b>Different color palettes</b>: color cannot alter the underlying numbers.</span><span class='qd'><b>Different chart types</b>: chart type changes presentation, not the totals computed from the same data.</span>" },
{ id:"D4-065", domain:4, obj:"4.3", diff:"medium", q:"A user clicks a 'Region = West' filter but the visuals do not change at all. Which is the BEST FIRST thing to check?", options:["Whether the filter is correctly connected/applied to the visuals' data source","Whether the title font is bold","Whether the logo is present","Whether the legend has the right color"], answer:0, explain:"<strong>Whether the filter is correctly connected/applied to the visuals' data source</strong> is the right first check, since a filter that is not wired to the visuals will have no effect.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the title font is bold</b>: title styling cannot cause a filter to be ignored.</span><span class='qd'><b>Whether the logo is present</b>: a logo is unrelated to filter behavior.</span><span class='qd'><b>Whether the legend has the right color</b>: legend color does not affect whether filters apply.</span>" },
{ id:"D4-066", domain:4, obj:"4.3", diff:"easy", q:"A report opens with garbled characters and missing values where text should be, suggesting the file or extract is damaged. This is BEST described as:", options:["Corrupt data","Slow refresh","Branding error","Excessive load time"], answer:0, explain:"<strong>Corrupt data</strong> describes data that is damaged or unreadable, producing garbled characters and missing values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slow refresh</b>: a slow refresh is a timing problem, not damaged content.</span><span class='qd'><b>Branding error</b>: branding concerns logos and styling, not garbled data.</span><span class='qd'><b>Excessive load time</b>: load time describes delay, not corrupted values.</span>" },
{ id:"D4-067", domain:4, obj:"4.3", diff:"hard", q:"A monthly revenue figure looks wrong. Before escalating, an analyst wants a second person to independently re-examine the calculation logic. Which validation technique is this?", options:["Increasing refresh frequency","Changing the color scheme","Peer review","Exporting to PDF"], answer:2, explain:"<strong>Peer review</strong> has another qualified person independently check the logic and results to catch errors before release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing refresh frequency</b>: more frequent refreshes do not verify whether the calculation is correct.</span><span class='qd'><b>Changing the color scheme</b>: recoloring cannot validate a numeric calculation.</span><span class='qd'><b>Exporting to PDF</b>: exporting just changes format and does not check correctness.</span>" },
{ id:"D4-068", domain:4, obj:"4.3", diff:"medium", q:"A dashboard total does not match the finance system. An analyst traces the figure back through the report's query to the original tables to confirm where it diverges. This technique is BEST called:", options:["Recurring scheduling","Adding tooltips","Source (data) validation","Choosing a new chart type"], answer:2, explain:"<strong>Source (data) validation</strong> verifies report figures against the authoritative source to find where and why they diverge.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recurring scheduling</b>: scheduling controls when a report runs, not whether its numbers are correct.</span><span class='qd'><b>Adding tooltips</b>: tooltips add hover detail and do not validate totals.</span><span class='qd'><b>Choosing a new chart type</b>: changing the chart does not reconcile the figure to the source.</span>" },
{ id:"D4-069", domain:4, obj:"4.3", diff:"medium", q:"Leadership wants to be notified automatically whenever daily error rates exceed 5% so they can act fast. Which capability BEST meets this need?", options:["A larger legend","A new font","A static PDF","Threshold-based monitoring alerts"], answer:3, explain:"<strong>Threshold-based monitoring alerts</strong> automatically notify stakeholders when a metric crosses a defined limit, exactly the 5% trigger requested.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger legend</b>: a legend does not monitor metrics or send notifications.</span><span class='qd'><b>A new font</b>: typography cannot detect or alert on threshold breaches.</span><span class='qd'><b>A static PDF</b>: a static PDF is passive and cannot trigger automated alerts.</span>" },
{ id:"D4-070", domain:4, obj:"4.3", diff:"hard", q:"After an upstream team renamed a source column from 'cust_id' to 'customer_id', a report broke. Which validation/monitoring practice would have caught this BEFORE users noticed?", options:["Using brighter colors","Automated schema/source monitoring with alerts on structure changes","Switching to a pie chart","Adding a watermark"], answer:1, explain:"<strong>Automated schema/source monitoring with alerts on structure changes</strong> detects column renames or type changes proactively so the report can be fixed before users hit errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using brighter colors</b>: color choices cannot detect a schema change upstream.</span><span class='qd'><b>Switching to a pie chart</b>: changing chart type does nothing to monitor source structure.</span><span class='qd'><b>Adding a watermark</b>: a watermark is decorative and provides no monitoring.</span>" },
{ id:"D4-071", domain:4, obj:"4.3", diff:"easy", q:"A dashboard's numbers have not changed in two weeks even though new sales occurred daily. Which issue is MOST likely?", options:["The font is too small","The data refresh has failed or is not scheduled (stale data)","The legend is missing","The colors are too bright"], answer:1, explain:"<strong>The data refresh has failed or is not scheduled (stale data)</strong> explains why figures are frozen despite ongoing daily sales.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The font is too small</b>: font size has no effect on whether data updates.</span><span class='qd'><b>The legend is missing</b>: a missing legend does not stop numbers from changing.</span><span class='qd'><b>The colors are too bright</b>: color cannot cause data to stop refreshing.</span>" },
{ id:"D4-072", domain:4, obj:"4.3", diff:"medium", q:"An analyst suspects a calculated field is wrong. The MOST direct way to confirm is to:", options:["Review the formula/code of the calculation step by step","Email the report to more people","Add additional charts","Increase the refresh frequency"], answer:0, explain:"<strong>Review the formula/code of the calculation step by step</strong> directly inspects the logic to find an error in the calculated field.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Email the report to more people</b>: wider distribution does not reveal a formula error.</span><span class='qd'><b>Add additional charts</b>: more charts do not verify the suspect calculation.</span><span class='qd'><b>Increase the refresh frequency</b>: refreshing more often will not fix or reveal incorrect logic.</span>" },
{ id:"D4-073", domain:4, obj:"4.3", diff:"hard", q:"A dashboard is slow only when many users open it at 9 a.m., but fast otherwise. Which cause is MOST consistent with this pattern?", options:["A missing axis title","An incorrect font","Concurrency/resource contention on the data source under peak load","A misplaced legend"], answer:2, explain:"<strong>Concurrency/resource contention on the data source under peak load</strong> explains slowness that appears only when many users query simultaneously at 9 a.m.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing axis title</b>: an absent title is a labeling issue with no performance impact.</span><span class='qd'><b>An incorrect font</b>: fonts do not vary speed by number of concurrent users.</span><span class='qd'><b>A misplaced legend</b>: legend placement cannot cause peak-time slowdowns.</span>" },
{ id:"D4-074", domain:4, obj:"4.3", diff:"medium", q:"A filter on a dashboard works for the bar chart but not the adjacent table. Which is the MOST likely explanation?", options:["The table uses a different font","The table has the wrong color","The table is too wide","The filter's scope does not include the table's data source/visual"], answer:3, explain:"<strong>The filter's scope does not include the table's data source/visual</strong> explains why one visual responds and another does not; the filter is simply not applied to the table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The table uses a different font</b>: fonts cannot determine whether a filter applies.</span><span class='qd'><b>The table has the wrong color</b>: color has no bearing on filter scope.</span><span class='qd'><b>The table is too wide</b>: width is a layout property and does not affect filtering.</span>" },
{ id:"D4-075", domain:4, obj:"4.3", diff:"easy", q:"Which practice involves having the report author re-read their own SQL and calculations carefully before publishing?", options:["Random color selection","Increasing chart count","Disabling alerts","Code/calculation review"], answer:3, explain:"<strong>Code/calculation review</strong> is the deliberate re-examination of one's own query and formula logic to catch mistakes before release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Random color selection</b>: choosing colors does nothing to verify logic.</span><span class='qd'><b>Increasing chart count</b>: adding charts does not validate the existing code.</span><span class='qd'><b>Disabling alerts</b>: turning off alerts removes monitoring rather than reviewing code.</span>" },
{ id:"D4-076", domain:4, obj:"4.3", diff:"hard", q:"A report shows a sudden, implausible 300% revenue jump for one day. Before publishing, the analyst should FIRST:", options:["Publish immediately because the tool computed it","Validate the figure against the source data to confirm or refute it","Change the chart to a pie","Make the font larger"], answer:1, explain:"<strong>Validate the figure against the source data to confirm or refute it</strong> is the responsible first step to determine whether the spike is real or an error before it misleads readers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish immediately because the tool computed it</b>: tools can compute on bad or duplicated data, so blind trust risks spreading errors.</span><span class='qd'><b>Change the chart to a pie</b>: changing chart type does not verify the suspicious value.</span><span class='qd'><b>Make the font larger</b>: typography is irrelevant to validating a figure.</span>" },
{ id:"D4-077", domain:4, obj:"4.3", diff:"medium", q:"An extract file is 4 GB and the BI tool runs out of memory rendering it. Which approach BEST reduces the data size while preserving the dashboard's purpose?", options:["Filter to needed columns/rows and aggregate to the required grain","Add more visuals","Use a fancier font","Change the legend position"], answer:0, explain:"<strong>Filter to needed columns/rows and aggregate to the required grain</strong> trims unnecessary detail so the extract fits in memory while still answering the business question.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more visuals</b>: adding visuals increases load rather than reducing data size.</span><span class='qd'><b>Use a fancier font</b>: fonts do not change the data volume.</span><span class='qd'><b>Change the legend position</b>: legend placement has no effect on file size or memory.</span>" },
{ id:"D4-078", domain:4, obj:"4.3", diff:"medium", q:"After a fix, a key metric still looks off and the analyst is unsure. Which step BEST increases confidence before release?", options:["Publish and hope no one notices","Have a peer independently reproduce and verify the result","Delete the metric","Hide the chart"], answer:1, explain:"<strong>Have a peer independently reproduce and verify the result</strong> applies peer review to confirm the metric, increasing confidence before release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish and hope no one notices</b>: this ignores the doubt and risks shipping an error.</span><span class='qd'><b>Delete the metric</b>: removing a needed metric avoids the problem instead of validating it.</span><span class='qd'><b>Hide the chart</b>: hiding the chart conceals rather than verifies the figure.</span>" },
{ id:"D4-079", domain:4, obj:"4.3", diff:"hard", q:"A dashboard's refresh succeeds but loads partial data because the source job was still writing when the extract ran. Which fix BEST prevents reading incomplete data?", options:["Recolor the charts","Add dependency/orchestration so the refresh starts only after the source load completes","Add a watermark","Increase the title size"], answer:1, explain:"<strong>Add dependency/orchestration so the refresh starts only after the source load completes</strong> sequences the jobs so the extract reads a finished, complete dataset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recolor the charts</b>: color cannot prevent reading a partially written source.</span><span class='qd'><b>Add a watermark</b>: a watermark is cosmetic and does not coordinate job timing.</span><span class='qd'><b>Increase the title size</b>: title size has no effect on refresh sequencing.</span>" },
{ id:"D4-080", domain:4, obj:"4.3", diff:"easy", q:"A monitoring rule sends an email when a daily KPI falls outside an expected range. The expected range that triggers the alert is called the:", options:["Threshold","Legend","Color scheme","Watermark"], answer:0, explain:"<strong>Threshold</strong> is the boundary value that, when crossed, triggers a monitoring alert.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Legend</b>: a legend maps colors to series and is not an alert boundary.</span><span class='qd'><b>Color scheme</b>: a color scheme styles visuals and does not define alert limits.</span><span class='qd'><b>Watermark</b>: a watermark is a background mark, not a trigger value.</span>" },
{ id:"D4-081", domain:4, obj:"4.3", diff:"medium", q:"A report ran fine yesterday but fails today with a 'column not found' error. Which root cause is MOST likely?", options:["An upstream data structure (schema) change","A change in chart color","A new font installation","A resized legend"], answer:0, explain:"<strong>An upstream data structure (schema) change</strong> such as a renamed or dropped column commonly causes a sudden 'column not found' failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A change in chart color</b>: color changes cannot produce a missing-column error.</span><span class='qd'><b>A new font installation</b>: installing fonts is unrelated to query columns.</span><span class='qd'><b>A resized legend</b>: legend size cannot break a data query.</span>" },
{ id:"D4-082", domain:4, obj:"4.3", diff:"hard", q:"An analyst wants to compare a slow dashboard's current behavior against last month to see what degraded. Which practice BEST enables this comparison over time?", options:["Changing the font weekly","Rotating chart colors","Adding more legends","Logging/monitoring of refresh durations and load metrics over time"], answer:3, explain:"<strong>Logging/monitoring of refresh durations and load metrics over time</strong> creates a performance history so current behavior can be compared against past baselines to find regressions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Changing the font weekly</b>: font changes generate no performance history.</span><span class='qd'><b>Rotating chart colors</b>: rotating colors does not record load metrics.</span><span class='qd'><b>Adding more legends</b>: legends contribute nothing to performance tracking.</span>" },
{ id:"D4-083", domain:4, obj:"4.3", diff:"medium", q:"A filter visually appears applied (shows 'West') but the chart still includes all regions. After confirming the filter is wired correctly, what should the analyst check NEXT?", options:["Whether the title is centered","Whether the logo is high-resolution","Whether the font is serif","Whether a conflicting filter or measure context overrides the selection"], answer:3, explain:"<strong>Whether a conflicting filter or measure context overrides the selection</strong> is the logical next check, since another filter or calculation context can negate the selected one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the title is centered</b>: title alignment cannot override a data filter.</span><span class='qd'><b>Whether the logo is high-resolution</b>: image quality has no effect on filtering.</span><span class='qd'><b>Whether the font is serif</b>: font style does not influence filter results.</span>" },
{ id:"D4-084", domain:4, obj:"4.3", diff:"easy", q:"Which of the following is a clear symptom of a report performance problem rather than a data-quality problem?", options:["Revenue totals are wrong","The dashboard takes several minutes to load","Customer names are misspelled","Dates are stored as text"], answer:1, explain:"<strong>The dashboard takes several minutes to load</strong> is a performance symptom about speed, distinct from data-quality issues that concern the values themselves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Revenue totals are wrong</b>: incorrect totals are a data-quality or calculation issue, not performance.</span><span class='qd'><b>Customer names are misspelled</b>: misspellings are a data-quality problem.</span><span class='qd'><b>Dates are stored as text</b>: a wrong data type is a data-quality/formatting issue, not load speed.</span>" },
{ id:"D4-085", domain:4, obj:"4.3", diff:"hard", q:"A nightly refresh sometimes succeeds with correct data and sometimes loads zero rows, seemingly at random. Which investigation step is MOST likely to reveal the cause?", options:["Try different chart colors each night","Change the report's font","Add a second legend","Review the refresh logs to correlate failures with source availability/timing"], answer:3, explain:"<strong>Review the refresh logs to correlate failures with source availability/timing</strong> uses recorded run history to pinpoint when and why the load returns no rows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Try different chart colors each night</b>: colors cannot reveal why a load returns zero rows.</span><span class='qd'><b>Change the report's font</b>: typography is irrelevant to intermittent load failures.</span><span class='qd'><b>Add a second legend</b>: a legend gives no insight into refresh behavior.</span>" },
{ id:"D4-086", domain:4, obj:"4.3", diff:"medium", q:"An analyst notices the report's KPI calculation divides by total orders but should divide by completed orders. The BEST corrective action is to:", options:["Recolor the KPI tile","Fix the calculation logic and re-validate against the source","Make the KPI font bold","Move the KPI to a new page"], answer:1, explain:"<strong>Fix the calculation logic and re-validate against the source</strong> corrects the wrong denominator and confirms the result is now accurate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Recolor the KPI tile</b>: color does not correct a wrong formula.</span><span class='qd'><b>Make the KPI font bold</b>: bolding text leaves the incorrect calculation in place.</span><span class='qd'><b>Move the KPI to a new page</b>: relocating the tile does not fix the math.</span>" },
{ id:"D4-087", domain:4, obj:"4.3", diff:"easy", q:"Which validation technique relies on a SECOND person rather than the original author to catch mistakes?", options:["Self code review","Peer review","Adding tooltips","Changing fonts"], answer:1, explain:"<strong>Peer review</strong> brings in another person to independently scrutinize the work, catching errors the author might miss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Self code review</b>: self review is done by the original author, not a second person.</span><span class='qd'><b>Adding tooltips</b>: tooltips add detail on hover and do not validate work.</span><span class='qd'><b>Changing fonts</b>: font changes do not verify correctness.</span>" },
{ id:"D4-088", domain:4, obj:"4.3", diff:"hard", q:"A dashboard correctly applies a date filter, but totals are still wrong because a duplicate join multiplies rows. Which validation BEST exposes this kind of inflation?", options:["Increase the refresh frequency","Reconcile row counts and totals against the source (source validation)","Switch chart colors","Add a watermark"], answer:1, explain:"<strong>Reconcile row counts and totals against the source (source validation)</strong> reveals that the report has more rows or larger totals than the source, exposing the duplicate-join inflation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the refresh frequency</b>: refreshing more often will not detect duplicated rows.</span><span class='qd'><b>Switch chart colors</b>: color cannot diagnose row inflation.</span><span class='qd'><b>Add a watermark</b>: a watermark provides no validation of totals.</span>" },
{ id:"D4-089", domain:4, obj:"4.3", diff:"medium", q:"A report's data is correct but it consistently loads slowly because it returns every column from a wide table. The BEST performance fix is to:", options:["Add a brighter color palette","Insert a company logo","Select only the columns the report actually uses","Bold the headers"], answer:2, explain:"<strong>Select only the columns the report actually uses</strong> reduces the data transferred and processed, directly improving load time on a wide table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add a brighter color palette</b>: color does not reduce the columns queried.</span><span class='qd'><b>Insert a company logo</b>: branding has no impact on query size.</span><span class='qd'><b>Bold the headers</b>: header styling does not affect performance.</span>" },
{ id:"D4-090", domain:4, obj:"4.3", diff:"hard", q:"Users see different numbers depending on when they open a live dashboard, and leadership wants one agreed figure for the daily standup. Which is the BEST approach?", options:["Tell users to refresh more often","Remove all filters","Publish a daily snapshot taken at a fixed time as the official figure","Change the dashboard colors"], answer:2, explain:"<strong>Publish a daily snapshot taken at a fixed time as the official figure</strong> gives everyone one consistent, agreed number for the standup despite the live data changing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tell users to refresh more often</b>: more refreshing makes the numbers diverge further, not converge.</span><span class='qd'><b>Remove all filters</b>: removing filters does not produce a single agreed point-in-time figure.</span><span class='qd'><b>Change the dashboard colors</b>: color changes cannot reconcile differing live values.</span>" },
{ id:"D4-091", domain:4, obj:"4.3", diff:"medium", q:"A report fails validation because a calculated growth rate uses last year's value as the numerator instead of the denominator. This is an example of an error best caught by:", options:["Increasing chart size","Changing the legend","Adding more colors","Reviewing the calculation logic"], answer:3, explain:"<strong>Reviewing the calculation logic</strong> catches a transposed numerator and denominator by inspecting the formula directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increasing chart size</b>: a larger chart does not reveal a formula mistake.</span><span class='qd'><b>Changing the legend</b>: legends do not validate calculations.</span><span class='qd'><b>Adding more colors</b>: color choices cannot detect a logic error.</span>" },
{ id:"D4-092", domain:4, obj:"4.3", diff:"easy", q:"Which of these BEST describes 'stale data' in a report?", options:["Data that is encrypted","Data shown in the wrong color","Data with a missing legend","Data that has not been refreshed and no longer reflects current reality"], answer:3, explain:"<strong>Data that has not been refreshed and no longer reflects current reality</strong> is the definition of stale data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data that is encrypted</b>: encryption protects data and is unrelated to freshness.</span><span class='qd'><b>Data shown in the wrong color</b>: color is presentation, not data currency.</span><span class='qd'><b>Data with a missing legend</b>: a missing legend is a clarity issue, not staleness.</span>" },
{ id:"D4-093", domain:4, obj:"4.3", diff:"hard", q:"A dashboard intermittently shows blank visuals for some users but not others. After ruling out their filters, the NEXT most useful check is:", options:["Whether their monitors support the brand colors","Whether they prefer a different font","Whether those users' permissions/row-level security return zero rows","Whether they enlarged the legend"], answer:2, explain:"<strong>Whether those users' permissions/row-level security return zero rows</strong> is the right next check, since access rules can legitimately return no data for certain users, blanking their visuals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether their monitors support the brand colors</b>: monitor color support cannot blank out data.</span><span class='qd'><b>Whether they prefer a different font</b>: font preference does not control returned rows.</span><span class='qd'><b>Whether they enlarged the legend</b>: legend size cannot cause blank visuals.</span>" },
{ id:"D4-094", domain:4, obj:"4.3", diff:"medium", q:"An analyst must prove a published number is trustworthy for an audit. Which combination of techniques BEST establishes this?", options:["Source validation plus peer review of the calculation","Brighter colors plus a bigger logo","A new font plus more gridlines","A pie chart plus a watermark"], answer:0, explain:"<strong>Source validation plus peer review of the calculation</strong> verifies the number against the authoritative source and has an independent reviewer confirm the logic, together establishing trust for an audit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brighter colors plus a bigger logo</b>: cosmetic changes do not prove a number is correct.</span><span class='qd'><b>A new font plus more gridlines</b>: typography and gridlines do not validate accuracy.</span><span class='qd'><b>A pie chart plus a watermark</b>: changing chart type and adding a mark do not verify the figure.</span>" },
{ id:"D4-095", domain:4, obj:"4.3", diff:"hard", q:"A real-time dashboard is both slow and occasionally shows partial numbers during peak refresh moments. Which single change addresses BOTH the load and the partial-data issue?", options:["Increase the font size","Add a second legend","Recolor every chart","Move to a scheduled pre-aggregated extract refreshed during off-peak hours"], answer:3, explain:"<strong>Move to a scheduled pre-aggregated extract refreshed during off-peak hours</strong> reduces live query load (speed) and serves a complete, finished dataset (no partial numbers), solving both problems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the font size</b>: typography affects neither speed nor data completeness.</span><span class='qd'><b>Add a second legend</b>: legends do not influence performance or partial data.</span><span class='qd'><b>Recolor every chart</b>: color changes resolve neither symptom.</span>" },
{ id:"D4-096", domain:4, obj:"4.3", diff:"medium", q:"A filter works in the desktop authoring tool but not after publishing to the server. Which is the MOST likely cause to investigate?", options:["The font rendered differently","The logo failed to upload","The legend changed color","A difference in the published data source/parameters or server configuration"], answer:3, explain:"<strong>A difference in the published data source/parameters or server configuration</strong> commonly explains behavior that works locally but breaks after publishing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The font rendered differently</b>: font rendering cannot disable a filter.</span><span class='qd'><b>The logo failed to upload</b>: a missing logo does not affect filter behavior.</span><span class='qd'><b>The legend changed color</b>: legend color has no bearing on filter function.</span>" },
{ id:"D4-097", domain:4, obj:"4.3", diff:"easy", q:"Which proactive practice notifies the team automatically when a daily refresh fails, rather than waiting for users to complain?", options:["Monitoring alerts on the refresh job","A larger title font","A new color palette","An extra legend"], answer:0, explain:"<strong>Monitoring alerts on the refresh job</strong> proactively notify the team of a failed refresh so they can act before users notice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger title font</b>: font size cannot detect a failed refresh.</span><span class='qd'><b>A new color palette</b>: colors do not monitor job status.</span><span class='qd'><b>An extra legend</b>: a legend provides no alerting capability.</span>" },
{ id:"D4-098", domain:4, obj:"4.3", diff:"hard", q:"A report's totals were correct last quarter but are now overstated. The team suspects a recent source change added duplicate records upstream. Which step BEST confirms the suspicion?", options:["Change the chart type to a treemap","Compare current source row counts to historical counts and validate keys for duplicates","Apply a darker color scheme","Increase the title font size"], answer:1, explain:"<strong>Compare current source row counts to historical counts and validate keys for duplicates</strong> directly tests whether duplicate records were introduced, confirming or refuting the overstatement cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change the chart type to a treemap</b>: a different chart cannot detect duplicate records.</span><span class='qd'><b>Apply a darker color scheme</b>: color has no diagnostic value for duplicates.</span><span class='qd'><b>Increase the title font size</b>: typography cannot reveal data duplication.</span>" },
{ id:"D4-099", domain:4, obj:"4.3", diff:"medium", q:"An analyst fixed a slow query but wants to confirm the dashboard now loads acceptably for end users before closing the ticket. The BEST final step is to:", options:["Assume it is fixed and close the ticket","Recolor the charts and close it","Measure the load time and validate the results, ideally with a peer or user check","Add a watermark and close it"], answer:2, explain:"<strong>Measure the load time and validate the results, ideally with a peer or user check</strong> confirms both that performance improved and that the data is still correct before closing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is fixed and close the ticket</b>: closing without verification risks reopening if the fix failed.</span><span class='qd'><b>Recolor the charts and close it</b>: recoloring does not verify the performance fix.</span><span class='qd'><b>Add a watermark and close it</b>: a watermark does nothing to confirm load time or accuracy.</span>" },
{ id:"D4-100", domain:4, obj:"4.3", diff:"hard", q:"After several incidents of broken reports from upstream changes, leadership asks for a lasting safeguard. Which solution BEST reduces future surprises across many reports?", options:["Tell each analyst to manually eyeball reports daily","Implement automated source/schema monitoring with alerts and a validation step in the pipeline","Standardize on one font across reports","Use brighter colors so errors stand out"], answer:1, explain:"<strong>Implement automated source/schema monitoring with alerts and a validation step in the pipeline</strong> systematically catches upstream changes and data problems before they reach users, scaling across many reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tell each analyst to manually eyeball reports daily</b>: manual checks do not scale and are unreliable across many reports.</span><span class='qd'><b>Standardize on one font across reports</b>: a uniform font does nothing to detect data or schema problems.</span><span class='qd'><b>Use brighter colors so errors stand out</b>: color cannot detect upstream changes or validate data.</span>" }
);
